changeSet.sql:
INSERT INTO default_role_template (id, code, name, description)
VALUES (gen_random_uuid(), 'ORGANIZATION_ADMIN', 'Organization Admin', 'Full access to all tenant resources');

INSERT INTO default_role_template_permission (role_template_id, permission_id)
SELECT drt.id, p.id
FROM default_role_template drt, permission p
WHERE drt.code = 'ORGANIZATION_ADMIN';
